1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  items: Item[];
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_SURCHARGE = 0.1;
13	const CURSE_SURCHARGE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
15	const HIGH_ENCHANTMENT_THRESHOLD = 5;
16	
17	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const COMPONENT_TYPES = ["rune", "moonstone"];
25	const COMPONENT_PREMIUM = 25;
26	const BLOCK_SIZE = 3;
27	const BLOCK_PREMIUM = 60;
28	
29	const isComponent = (item: Item): boolean =>
30	  COMPONENT_TYPES.includes(item.type);
31	
32	const isMainItem = (item: Item): boolean => !isComponent(item);
33	
34	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
35	// BLOCK_PREMIUM; any other count is priced per component.
36	const componentGroupBasePremium = (count: number): number =>
37	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
38	
39	// An item-specific surcharge adds `rate` of the item's base premium when its
40	// condition holds, and nothing otherwise.
41	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
42	  applies ? rate * basePremiumForItem(item) : 0;
43	
44	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
45	const curseSurcharge = (item: Item): number =>
46	  surchargeWhen(item, item.cursed ?? false, CURSE_SURCHARGE);
47	
48	// Highly enchanted items (enchantment at or above the threshold) add a
49	// surcharge equal to HIGH_ENCHANTMENT_SURCHARGE of their base premium.
50	const highEnchantmentSurcharge = (item: Item): number =>
51	  surchargeWhen(
52	    item,
53	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
54	    HIGH_ENCHANTMENT_SURCHARGE,
55	  );
56	
57	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
58	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
59	// that is only spuriously above a whole number.
60	const roundUpInMHPCOsFavor = (amount: number): number =>
61	  Math.ceil(Number(amount.toFixed(6)));
62	
63	const basePremiumForItem = (item: Item): number =>
64	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
65	
66	// Each main item is priced on its own.
67	const mainItemsBasePremium = (items: Item[]): number =>
68	  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
69	
70	const countByType = (items: Item[]): Map<string, number> => {
71	  const counts = new Map<string, number>();
72	  for (const item of items) {
73	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
74	  }
75	  return counts;
76	};
77	
78	// Components are grouped by type, and each group is block-priced.
79	const componentsBasePremium = (components: Item[]): number =>
80	  [...countByType(components).values()].reduce(
81	    (sum, count) => sum + componentGroupBasePremium(count),
82	    0,
83	  );
84	
85	const policyBasePremium = (items: Item[]): number =>
86	  mainItemsBasePremium(items.filter(isMainItem)) +
87	  componentsBasePremium(items.filter(isComponent));
88	
89	// Tier 1 — item-specific surcharges: computed off each affected item's base
90	// premium and summed across the policy. (e.g. curse; later high-enchantment.)
91	const itemSurcharges = (items: Item[]): number =>
92	  items.reduce(
93	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
94	    0,
95	  );
96	
97	// Tier 2 — policy-wide modifiers: computed as a fraction of the policy base
98	// premium. (e.g. first-insurance surcharge; later loyalty/follow-up discounts.)
99	const policyWideModifiers = (policyBase: number): number =>
100	  FIRST_INSURANCE_SURCHARGE * policyBase;
101	
102	export const quote = (
103	  customer: unknown,
104	  step: QuoteStep,
105	  quoteIndex: number,
106	): number => {
107	  const policyBase = policyBasePremium(step.items);
108	
109	  const total =
110	    policyBase +
111	    itemSurcharges(step.items) +
112	    policyWideModifiers(policyBase) +
113	    PROCESSING_FEE;
114	  return roundUpInMHPCOsFavor(total);
115	};
116	
117	export const claim = (...args: unknown[]): unknown => {
118	  return undefined; // Intentionally not implemented
119	};
120

